							totalCount: 0
						}
					}
				})
			});
			return;
		}
		if (body.query.includes('RunBundleFileFetch')) {
			const path = body.variables?.['path'] as string;
			let payload: {
				path: string;
				content: string | null;
				sizeBytes: number;
				truncated: boolean;
				mimeType: string;
			};
			if (path === 'prompt.md') {
				payload = {
					path,
					content: '# Sample prompt\nbody text',
					sizeBytes: 128,
					truncated: false,
					mimeType: 'text/markdown'
				};
			} else if (path === 'screenshots/big.png') {
				payload = {
					path,
					content: null,
					sizeBytes: 200_000,
					truncated: true,
					mimeType: 'image/png'
				};
			} else {
				payload = {
					path,
					content: '{"ok":true}',
					sizeBytes: 256,
					truncated: false,
					mimeType: 'application/json'
				};
			}
			await route.fulfill({
				status: 200,
				contentType: 'application/json',
				body: JSON.stringify({ data: { runBundleFile: payload } })
			});
			return;
		}
		if (body.query.includes('ProducedArtifact')) {
			await route.fulfill({
				status: 200,
				contentType: 'application/json',
				body: JSON.stringify({ data: { artifact: null } })
			});
			return;
		}
		await route.continue();
	});

	// Navigate directly to evidence tab
